  return Promise.resolve([{ title: "Post 1" }, { title: "Post 2" }]);
}

async function loadUserPosts() {
  try {
    const user = await fetchUser(1);
    const posts = await fetchPosts(user.id);
    return posts.length;
  } catch (err) {
    return "Error: " + err;
  }
}

