// safeLoad wraps any promise and normalizes the result:
// { ok: true, data: value }    on resolve
// { ok: false, error: message } on reject
async function safeLoad(promise) {
  // Your code here
}

challenges.solution:
async function safeLoad(promise) {
  try {
    const value = await promise;
    return { ok: true, data: value };
  } catch (err) {
    return { ok: false, error: err };
  }
}
